import React from 'react';
import { PredictedMatch } from '../types';
import { ViewMode } from './EventView';

interface MatchCardProps {
  match: PredictedMatch;
  viewMode: ViewMode;
  teamOPRs: Map<number, number>;
}

const MatchCard: React.FC<MatchCardProps> = ({ match, viewMode, teamOPRs }) => {
  const useActual = viewMode === 'actual' && match.hasBeenPlayed;
  const winner = useActual ? match.actualWinner : match.predictedWinner;
  const redScore = useActual ? match.actualRedScore : match.redPredictedScore;
  const blueScore = useActual ? match.actualBlueScore : match.bluePredictedScore;
  const showOPR = !useActual;

  const cardClass = [
    'match-card',
    winner === 'red' ? 'mc-red-win' : winner === 'blue' ? 'mc-blue-win' : '',
    !match.hasBeenPlayed ? 'mc-upcoming' : '',
  ].filter(Boolean).join(' ');

  return (
    <div className={cardClass}>
      <div className="mc-header">
        <span className="mc-num">Match {match.matchNum}</span>
        <span className={`mc-badge ${match.hasBeenPlayed ? 'badge-played' : 'badge-upcoming'}`}>
          {match.hasBeenPlayed ? 'PLAYED' : 'UPCOMING'}
        </span>
      </div>

      <div className="mc-body">
        <AllianceBlock
          color="red"
          teams={match.redTeams}
          score={redScore}
          isWinner={winner === 'red'}
          showOPR={showOPR}
          teamOPRs={teamOPRs}
          useActual={useActual}
        />

        <div className="mc-vs">
          <span className="vs-text">VS</span>
          {winner === 'red' && <span className="arrow-left">◄</span>}
          {winner === 'blue' && <span className="arrow-right">►</span>}
        </div>

        <AllianceBlock
          color="blue"
          teams={match.blueTeams}
          score={blueScore}
          isWinner={winner === 'blue'}
          showOPR={showOPR}
          teamOPRs={teamOPRs}
          useActual={useActual}
        />
      </div>

      {winner && (
        <div className="mc-footer">
          <span className={`win-badge wb-${winner === 'tie' ? 'tie' : winner}`}>
            {winner === 'tie' ? '🤝 TIE' : `${winner.toUpperCase()} WINS`}
          </span>
        </div>
      )}
    </div>
  );
};

interface AllianceBlockProps {
  color: 'red' | 'blue';
  teams: number[];
  score: number | undefined;
  isWinner: boolean;
  showOPR: boolean;
  teamOPRs: Map<number, number>;
  useActual: boolean;
}

const AllianceBlock: React.FC<AllianceBlockProps> = ({
  color, teams, score, isWinner, showOPR, teamOPRs, useActual,
}) => (
  <div className={`alliance-blk ab-${color}${isWinner ? ' ab-winner' : ''}`}>
    <div className={`ab-label ab-label-${color}`}>{color.toUpperCase()}</div>
    <div className="ab-teams">
      {teams.map(num => (
        <div key={num} className={`team-pill tp-${color}`}>
          <span className="tp-num">#{num}</span>
          {showOPR && (
            <span className="tp-opr">{(teamOPRs.get(num) ?? 0).toFixed(1)}</span>
          )}
        </div>
      ))}
    </div>
    <div className={`ab-score score-${color}${isWinner ? ' score-winner' : ''}`}>
      {score != null
        ? useActual
          ? Math.round(score)
          : score.toFixed(1)
        : '—'}
    </div>
    {showOPR && (
      <div className="ab-opr-label">OPR sum</div>
    )}
  </div>
);

export default MatchCard;
